import json
import ast
import re

# Load business data from file
business_file_path = var_functions__query_db__5
with open(business_file_path, 'r') as f:
    business_data = json.load(f)

# Review data
review_data = var_functions__query_db__6

# Convert review data to dict for easier lookup
review_dict = {}
for item in review_data:
    review_dict[item['gmap_id']] = float(item['avg_rating'])

# Function to parse hours string and check if business closes after 6PM on any weekday
def closes_after_6pm(weekday_hours):
    if not weekday_hours or weekday_hours == 'Closed':
        return False

    closing = weekday_hours.upper()

    # Check for 24 hours
    if '24 HOURS' in closing or '24H' in closing:
        return True

    # Find closing time (after dash)
    if '–' in weekday_hours:
        times = weekday_hours.split('–')
    elif '-' in weekday_hours:
        times = weekday_hours.split('-')
    else:
        return False

    if len(times) < 2:
        return False

    closing_time = times[1].strip().upper()

    # Check PM times
    if 'PM' in closing_time:
        hour_match = re.search(r'(\d+)', closing_time)
        if hour_match:
            hour = int(hour_match.group(1))
            if hour < 12:  # PM but not noon
                hour_24 = hour + 12
            else:
                hour_24 = hour
            return hour_24 >= 18

    # Check early AM (crosses midnight)
    if 'AM' in closing_time:
        hour_match = re.search(r'(\d+)', closing_time)
        if hour_match:
            hour = int(hour_match.group(1))
            if hour < 6:
                return True

    return False

def has_weekday_evening_hours(hours_str):
    if not hours_str or hours_str == 'None':
        return False

    try:
        hours_list = ast.literal_eval(hours_str)
        weekdays = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']

        for day_info in hours_list:
            if len(day_info) >= 2:
                day_name = day_info[0]
                hours = day_info[1]
                if day_name in weekdays and closes_after_6pm(hours):
                    return True

        return False
    except:
        return False

# Process businesses
eligible = []
for b in business_data:
    gmap_id = b['gmap_id']
    if has_weekday_evening_hours(b['hours']):
        avg_rating = review_dict.get(gmap_id, 0.0)
        eligible.append({
            'name': b['name'],
            'hours': b['hours'],
            'avg_rating': round(avg_rating, 2),
            'gmap_id': gmap_id
        })

# Sort and get top 5
top5 = sorted(eligible, key=lambda x: x['avg_rating'], reverse=True)[:5]

result = json.dumps(top5, indent=2)
print('__RESULT__:')
print(result)

